#include <omp.h>
#include <stdio.h>
#include <stdlib.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void lud_diagonal(float *m, int matrix_dim, int offset) {
    int i, j;
    float shadow[BLOCK_SIZE * BLOCK_SIZE];
    int tx;

    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx];
            array_offset += matrix_dim;
        }
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        #pragma omp parallel for private(j) shared(shadow, i)
        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i; j++)
                shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
            shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
        }

        #pragma omp barrier

        #pragma omp parallel for private(j) shared(shadow, i)
        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i + 1; j++)
                shadow[(i + 1) * BLOCK_SIZE + tx] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
        }

        #pragma omp barrier
    }

    int array_offset = (offset + 1) * matrix_dim + offset;
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        for (i = 1; i < BLOCK_SIZE; i++) {
            m[array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
            array_offset += matrix_dim;
        }
        array_offset = (offset + 1) * matrix_dim + offset;
    }
}

void lud_perimeter(float *m, int matrix_dim, int offset) {
    int i, j, array_offset;
    int idx;
    float dia[BLOCK_SIZE * BLOCK_SIZE];
    float peri_row[BLOCK_SIZE * BLOCK_SIZE];
    float peri_col[BLOCK_SIZE * BLOCK_SIZE];

    int bx, tx;

    int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;
    if (num_blocks < 0) return;

    for (bx = 0; bx < num_blocks; bx++) {
        #pragma omp parallel for private(i, idx, array_offset, j, tx) shared(m, dia, peri_row, peri_col, matrix_dim, offset, bx)
        for (tx = 0; tx < 2 * BLOCK_SIZE; tx++) {
            if (tx < BLOCK_SIZE) {
                idx = tx;
                array_offset = offset * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE / 2; i++) {
                    dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                    array_offset += matrix_dim;
                }

                array_offset = offset * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    peri_row[i * BLOCK_SIZE + idx] = m[array_offset + (bx + 1) * BLOCK_SIZE + idx];
                    array_offset += matrix_dim;
                }
            } else {
                idx = tx - BLOCK_SIZE;

                array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
                for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
                    dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                    array_offset += matrix_dim;
                }

                array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    peri_col[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                    array_offset += matrix_dim;
                }
            }
        }

        #pragma omp barrier

        #pragma omp parallel for private(i, j, idx, tx) shared(dia, peri_row, peri_col)
        for (tx = 0; tx < 2 * BLOCK_SIZE; tx++) {
            if (tx < BLOCK_SIZE) {
                idx = tx;
                for (i = 1; i < BLOCK_SIZE; i++) {
                    for (j = 0; j < i; j++)
                        peri_row[i * BLOCK_SIZE + idx] -= dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + idx];
                }
            } else {
                idx = tx - BLOCK_SIZE;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    for (j = 0; j < i; j++)
                        peri_col[idx * BLOCK_SIZE + i] -= peri_col[idx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
                    peri_col[idx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
                }
            }
        }

        #pragma omp barrier

        #pragma omp parallel for private(i, idx) shared(m, peri_row, peri_col, matrix_dim, offset, bx)
        for (tx = 0; tx < 2 * BLOCK_SIZE; tx++) {
            if (tx < BLOCK_SIZE) {
                idx = tx;
                array_offset = (offset + 1) * matrix_dim + offset;
                for (i = 1; i < BLOCK_SIZE; i++) {
                    m[array_offset + (bx + 1) * BLOCK_SIZE + idx] = peri_row[i * BLOCK_SIZE + idx];
                    array_offset += matrix_dim;
                }
            } else {
                idx = tx - BLOCK_SIZE;
                array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    m[array_offset + idx] = peri_col[i * BLOCK_SIZE + idx];
                    array_offset += matrix_dim;
                }
            }
        }
    }
}

void lud_internal(float *m, int matrix_dim, int offset) {
    int bx, by, tx, ty, i;
    float sum;

    int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;
    if (num_blocks < 0) return;

    #pragma omp parallel for collapse(2) private(bx, by, tx, ty, i, sum) shared(m, matrix_dim, offset)
    for (by = 0; by < num_blocks; by++) {
        for (bx = 0; bx < num_blocks; bx++) {
            float peri_row[BLOCK_SIZE * BLOCK_SIZE];
            float peri_col[BLOCK_SIZE * BLOCK_SIZE];

            // Load peri_row and peri_col
            for (ty = 0; ty < BLOCK_SIZE; ty++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    int global_row_id = offset + (by + 1) * BLOCK_SIZE;
                    int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

                    peri_row[ty * BLOCK_SIZE + tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
                    peri_col[ty * BLOCK_SIZE + tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];
                }
            }

            // Compute and update m
            for (ty = 0; ty < BLOCK_SIZE; ty++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    sum = 0.0f;
                    for (i = 0; i < BLOCK_SIZE; i++)
                        sum += peri_col[ty * BLOCK_SIZE + i] * peri_row[i * BLOCK_SIZE + tx];
                    int global_row_id = offset + (by + 1) * BLOCK_SIZE;
                    int global_col_id = offset + (bx + 1) * BLOCK_SIZE;
                    m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
                }
            }
        }
    }
}

void lud_omp(float *m, int matrix_dim) {
    int i;
    int num_blocks = matrix_dim / BLOCK_SIZE;

    for (i = 0; i < num_blocks; i++) {
        lud_diagonal(m, matrix_dim, i * BLOCK_SIZE);
        if (i < num_blocks - 1) {
            lud_perimeter(m, matrix_dim, i * BLOCK_SIZE);
            lud_internal(m, matrix_dim, i * BLOCK_SIZE);
        }
    }
}
